const crypto = require('crypto');

function deserializeSessionCookie(cookieValue) {
  try {
    const encryptedData = Buffer.from(cookieValue, 'base64').toString('utf-8');
    const [userId, username, email, loginTime, expiration] = JSON.parse(crypto.AES.decrypt(encryptedData, process.env.SESSION_SECRET).toString(crypto.enc.Utf8));

    return {
      userId,
      username,
      email,
      loginTime,
      expiration,
    };
  } catch (error) {
    console.error('Error deserializing session cookie:', error);
    return null;
  }
}